index 553435c937a7..f648ec3bce77 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -926,6 +926,7 @@ Instruction *InstCombinerImpl::foldBinOpShiftWithShift(BinaryOperator &I) {

     // Otherwise, need mask that meets the below requirement.
     // (logic_shift (inv_logic_shift Mask, ShAmt), ShAmt) == Mask
+
     Constant *MaskInvShift =
         ConstantFoldBinaryOpOperands(GetInvShift(ShOpc), CMask, CShift, DL);
     return ConstantFoldBinaryOpOperands(ShOpc, MaskInvShift, CShift, DL) ==
@@ -935,29 +936,34 @@ Instruction *InstCombinerImpl::foldBinOpShiftWithShift(BinaryOperator &I) {
   auto MatchBinOp = [&](unsigned ShOpnum) -> Instruction * {
     Constant *CMask, *CShift;
     Value *X, *Y, *ShiftedX, *Mask, *Shift;
+    // Match one operand as a single-use shift: Y << S
     if (!match(I.getOperand(ShOpnum),
                m_OneUse(m_Shift(m_Value(Y), m_Value(Shift)))))
       return nullptr;
+
+    // Match the other operand as a binary operation: e.g., Z ^ (X << S)
     if (!match(I.getOperand(1 - ShOpnum),
                m_BinOp(m_Value(ShiftedX), m_Value(Mask))))
       return nullptr;

+    // Match the value inside the binop as a shift: X << S (same shift amount)
     if (!match(ShiftedX, m_OneUse(m_Shift(m_Value(X), m_Specific(Shift)))))
       return nullptr;

-    // Make sure we are matching instruction shifts and not ConstantExpr
+    // Ensure both shifts are actual instructions (not constant expressions)
     auto *IY = dyn_cast<Instruction>(I.getOperand(ShOpnum));
     auto *IX = dyn_cast<Instruction>(ShiftedX);
     if (!IY || !IX)
       return nullptr;

-    // LHS and RHS need same shift opcode
+    // Both shifts must have the same opcode (e.g., shl, lshr, etc.)
     unsigned ShOpc = IY->getOpcode();
     if (ShOpc != IX->getOpcode())
       return nullptr;

     // Make sure binop is real instruction and not ConstantExpr
     auto *BO2 = dyn_cast<Instruction>(I.getOperand(1 - ShOpnum));
+
     if (!BO2)
       return nullptr;

messages.content:
This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
define i8 @xor_shl(i8 %x, i8 %y, i8 %zarg, i8 %shamt) {
  %z = sdiv i8 42, %zarg
  %sx = shl i8 %x, %shamt
  %sy = shl i8 %y, %shamt
  %a = xor i8 %z, %sx
  %r = xor i8 %a, %sy
  ret i8 %r
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i8 @xor_shl(i8 %x, i8 %y, i8 %zarg, i8 %shamt) {
  %z = sdiv i8 42, %zarg
  %1 = xor i8 %x, %y
  %2 = shl i8 %1, %shamt
  %r = xor i8 %2, %z
  ret i8 %r
}

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstructionCombining.cpp:InstCombinerImpl::foldBinOpShiftWithShift to implement the missed optimization:
```cpp
    Constant *MaskInvShift =
        ConstantFoldBinaryOpOperands(GetInvShift(ShOpc), CMask, CShift, DL);
    return ConstantFoldBinaryOpOperands(ShOpc, MaskInvShift, CShift, DL) ==
           CMask;
  };

  auto MatchBinOp = [&](unsigned ShOpnum) -> Instruction * {
    Constant *CMask, *CShift;
    Value *X, *Y, *ShiftedX, *Mask, *Shift;
    if (!match(I.getOperand(ShOpnum),
               m_OneUse(m_Shift(m_Value(Y), m_Value(Shift)))))
      return nullptr;
    if (!match(I.getOperand(1 - ShOpnum),
               m_BinOp(m_Value(ShiftedX), m_Value(Mask))))
      return nullptr;

    if (!match(ShiftedX, m_OneUse(m_Shift(m_Value(X), m_Specific(Shift)))))
      return nullptr;

    // Make sure we are matching instruction shifts and not ConstantExpr
    auto *IY = dyn_cast<Instruction>(I.getOperand(ShOpnum));
    auto *IX = dyn_cast<Instruction>(ShiftedX);
    if (!IY || !IX)
      return nullptr;

    // LHS and RHS need same shift opcode
    unsigned ShOpc = IY->getOpcode();
    if (ShOpc != IX->getOpcode())
      return nullptr;

    // Make sure binop is real instruction and not ConstantExpr
    auto *BO2 = dyn_cast<Instruction>(I.getOperand(1 - ShOpnum));
```

